import { useEffect, useMemo, useState } from "react";
import api from "../api";

function fmtMoney(v) {
    const n = Number(v || 0);
    try { return n.toLocaleString("vi-VN") + " ₫"; } catch { return n + " ₫"; }
}
function addDaysISO(iso, days) {
    if (!iso || typeof days !== "number") return "";
    const t = new Date(iso);
    if (Number.isNaN(t.getTime())) return "";
    t.setDate(t.getDate() + days);
    return t.toISOString().slice(0,10);
}

export default function Contracts() {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(0);
    const size = 9;
    const [totalPages, setTotalPages] = useState(1);

    const [customersMap, setCustomersMap] = useState({}); // id -> name

    // nạp map khách hàng một lần (tối đa 1000)
    useEffect(() => { (async () => {
        try {
            const res = await api.get("/api/customers", { params: { page: 0, size: 1000 }});
            const content = Array.isArray(res.data) ? res.data : (res.data?.content || []);
            const map = {};
            content.forEach(c => map[c.id] = c.name);
            setCustomersMap(map);
        } catch {}
    })(); }, []);

    useEffect(() => { load(); }, [page]);

    async function load() {
        setLoading(true);
        try {
            const res = await api.get("/api/contracts", { params: { page, size, sort: "id,desc" }});
            const data = res.data || {};
            const content = Array.isArray(data) ? data : (data.content || []);
            setRows(content);
            setTotalPages((Array.isArray(data) ? 1 : (data.totalPages ?? 1)) || 1);
        } catch (e) {
            console.error(e);
            setRows([]); setTotalPages(1);
        } finally { setLoading(false); }
    }

    const normalized = useMemo(() => rows.map(c => {
        const code = c.code || c.contractCode || c.title || (`HD-${c.id}`);
        const value = c.totalAmount ?? c.value ?? c.contractValue ?? 0;
        const signed = c.signedDate || c.signed || c.signDate || (c.createdAt ? String(c.createdAt).slice(0,10) : "");
        const duration = c.duration ?? c.termDays ?? null;
        const dueDate = c.dueDate || (duration ? addDaysISO(signed, duration) : c.endDate) || "";
        const type = c.contractType || c.type || "";
        const status = c.status || c.contractStatus || "Đang thực hiện";
        const customerName =
            c.customerName ||
            c.customer?.name ||
            (c.customerId ? customersMap[c.customerId] : "") ||
            "";

        return { id: c.id, code, value, signed, dueDate, type, status, customerName };
    }), [rows, customersMap]);

    return (
        <div className="p-6">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold">📑 Hợp đồng</h2>
                <div className="text-sm text-slate-600">Trang {page+1}/{totalPages}</div>
            </div>

            {loading ? <p>Đang tải...</p> : (
                <>
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                        {normalized.map(c => (
                            <div key={c.id} className="p-4 rounded-2xl bg-white border border-indigo-100 shadow flex flex-col gap-3">
                                <div className="flex items-start justify-between">
                                    <div>
                                        <div className="font-semibold">{c.code}</div>
                                        <div className="text-sm text-slate-600">{c.customerName || "-"}</div>
                                        <div className="text-xs text-slate-500 mt-1">
                                            {c.type} • Ký: {c.signed || "-"} {c.dueDate ? `• Hạn: ${c.dueDate}` : ""}
                                        </div>
                                    </div>
                                    <span className={
                                        "px-2 py-0.5 rounded-full text-xs " +
                                        (c.status === "Đã hoàn tất"
                                            ? "bg-emerald-100 text-emerald-700"
                                            : c.status === "Huỷ"
                                                ? "bg-rose-100 text-rose-700"
                                                : "bg-amber-100 text-amber-700")
                                    }>
                    {c.status}
                  </span>
                                </div>

                                <div className="grid grid-cols-3 gap-3">
                                    <div className="p-3 rounded-xl bg-indigo-50/50">
                                        <div className="text-xs text-slate-500">Giá trị</div>
                                        <div className="font-semibold">{fmtMoney(c.value)}</div>
                                    </div>
                                    {/* Bạn có thể tính ĐÃ THU/CÒN LẠI bằng cách gọi /api/payments?contractId=... */}
                                    <div className="p-3 rounded-xl bg-slate-50">
                                        <div className="text-xs text-slate-500">Đã thu</div>
                                        <div className="font-semibold">—</div>
                                    </div>
                                    <div className="p-3 rounded-xl bg-slate-50">
                                        <div className="text-xs text-slate-500">Còn lại</div>
                                        <div className="font-semibold">—</div>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="flex gap-2 mt-4">
                        <button disabled={page<=0}
                                onClick={()=>setPage(p=>Math.max(0, p-1))}
                                className="px-3 py-1 rounded bg-slate-100 disabled:opacity-50">
                            ← Trước
                        </button>
                        <button disabled={page+1>=totalPages}
                                onClick={()=>setPage(p=>p+1)}
                                className="px-3 py-1 rounded bg-slate-100 disabled:opacity-50">
                            Sau →
                        </button>
                    </div>
                </>
            )}
        </div>
    );
}
